```csharp
using UnityEngine;

public class Player : MonoBehaviour
{
    void OnCollisionEnter2D(Collision2D collision)
    {
        // Check if the collision is with the ground
        if (collision.gameObject.CompareTag("Ground"))
        {
            // Adjust the player's position to be on top of the ground
            Vector2 groundPosition = collision.transform.position;
            groundPosition.y += collision.collider.bounds.extents.y; // Adjust by half the height of the ground collider
            transform.position = groundPosition;
        }
    }
}
```

4. **Decorate with Tags**: To make your script work, you need to tag the ground. Select the ground sprite, then go to the "Inspector" and add a tag named "Ground". You can do this by clicking on "Create Tag" in the "Inspector".

